import { GoogleGenAI, Type } from "@google/genai";
import { SiteSuggestion } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const getSiteSuggestion = async (userInput: string): Promise<SiteSuggestion> => {
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Suggest a 2-5 page website structure for this idea: ${userInput}. 
               Keep it practical for a startup or personal site.`,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          businessType: { type: Type.STRING },
          recommendedPages: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                description: { type: Type.STRING }
              },
              required: ["title", "description"]
            }
          },
          whyThisWorks: { type: Type.STRING }
        },
        required: ["businessType", "recommendedPages", "whyThisWorks"]
      }
    }
  });

  return JSON.parse(response.text);
};

