      <div className="bg-white rounded-3xl shadow-xl shadow-slate-200/50 p-6 md:p-10 border border-slate-100">
        <div className="flex flex-col md:flex-row gap-4 mb-8">
          <input
            type="text"
            value={input}
            onChange={(e) => setInput(e.target.value)}
            placeholder="e.g., A local coffee shop with a focus on organic beans..."
            className="flex-1 px-6 py-4 rounded-2xl bg-slate-50 border border-slate-200 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:bg-white transition-all"
          />
          <button
            onClick={handlePlan}
            disabled={loading}
            className={`px-8 py-4 rounded-2xl font-bold text-white shadow-lg transition-all ${
              loading ? 'bg-slate-400 cursor-not-allowed' : 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100'
            }`}
          >
            {loading ? 'Thinking...' : 'Generate Plan'}
