        </div>

        {suggestion && (
          <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
            <div className="mb-6 pb-6 border-b border-slate-100">
              <h3 className="text-xl font-bold text-slate-900 mb-1">Tailored for: {suggestion.businessType}</h3>
              <p className="text-slate-500 text-sm italic">{suggestion.whyThisWorks}</p>
            </div>

            <div className="space-y-4">
              {suggestion.recommendedPages.map((page, idx) => (
                <div key={idx} className="flex items-start gap-4 p-4 rounded-2xl bg-indigo-50/50 border border-indigo-100">
                  <div className="w-8 h-8 rounded-full bg-indigo-600 text-white flex items-center justify-center font-bold text-xs shrink-0">
